module RefModule (D, CLK, LOAD, SHIFT, Q);
input [7:0] D;
input CLK, LOAD, SHIFT;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (LOAD) begin
        Q <= D;
    end
    else if (SHIFT) begin
        Q <= Q << 1;
    end
end

endmodule
